import{_ as t,o as a,c as i,ao as s}from"./chunks/framework.COeXiFAf.js";const d=JSON.parse('{"title":"Contributing","description":"","frontmatter":{},"headers":[],"relativePath":"contributing.md","filePath":"contributing.md","lastUpdated":null}'),o={name:"contributing.md"};function n(r,e,l,h,p,u){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="Contributing" tabindex="-1">Contributing <a class="header-anchor" href="#Contributing" aria-label="Permalink to &quot;Contributing {#Contributing}&quot;">​</a></h1><p>Contributions to FlexiChains are very much welcome, either in the form of issues or pull requests! If you&#39;d like to discuss a potential new feature or improvement please also don&#39;t hesitate to open an issue.</p><p>In particular, I am very keen to to improve interoperability with the wider Julia ecosystem (e.g. via package extensions). If you have a package that you think could benefit from some custom behaviour with FlexiChains please do reach out!</p><h2 id="Formatting" tabindex="-1">Formatting <a class="header-anchor" href="#Formatting" aria-label="Permalink to &quot;Formatting {#Formatting}&quot;">​</a></h2><p>FlexiChains currently uses <a href="https://github.com/JuliaEditorSupport/JuliaFormatter.jl/" target="_blank" rel="noreferrer">JuliaFormatter.jl</a> for formatting, specifically, <strong>version 2.10.1</strong>. This is enforced on GitHub CI.</p><p>JuliaFormatter can be a tiny bit slow which is annoying if you are running it via pre-commit. <a href="https://juliaeditorsupport.github.io/JuliaFormatter.jl/stable/packagecompiler/" target="_blank" rel="noreferrer">The JuliaFormatter docs have a few tips for how to work around this.</a></p><h2 id="Tests" tabindex="-1">Tests <a class="header-anchor" href="#Tests" aria-label="Permalink to &quot;Tests {#Tests}&quot;">​</a></h2><p>To run the tests you can run <code>julia --project=.</code> from the root of the repository, and then run <code>]test</code> from the REPL, much like any other Julia package.</p><p>Equivalently, you can also run</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; Pkg.test()&#39;</span></span></code></pre></div><p>The tests in FlexiChains are also set up to work with <a href="https://github.com/theogf/TestPicker.jl" target="_blank" rel="noreferrer">TestPicker.jl</a> which allows you to run a subset of the tests by entering <code>!</code> at the Julia REPL.</p><p>FlexiChains contains some tests for plotting, which compare the output of the plotting functions against reference images. The reference images are stored in <code>test/plots/images</code> and are part of the repository itself.</p><p>If these need to be updated (e.g. because FlexiChains&#39; plotting functionality has changed, or because of changes in the underlying plotting libraries), the reference images can be updated by running</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>UPDATE_REFIMAGES=1 julia --project=. -e &#39;using Pkg; Pkg.test()&#39;</span></span></code></pre></div><p>This will skip all other tests and only rerun the plotting tests to update the reference images.</p>',15)])])}const g=t(o,[["render",n]]);export{d as __pageData,g as default};
